/**
 * Detail emitted by `food-log-detail` when the user presses "Log Food".
 * Discriminated by `kind`:
 *   - `existing`: the food item already exists; the parent posts a consumption entry.
 *   - `new`: the food item doesn't exist yet (e.g. an OFF product the user just
 *     picked); the parent calls the combined create+log endpoint so the food
 *     row and the consumption row commit atomically — no orphan on failure.
 */
export interface FoodLogEntryExisting {
    kind: 'existing';
    food_item_id: string;
    meal_type: MealType;
    amount: number;
    calories?: number;
    protein_g?: number;
    carbs_g?: number;
    fat_g?: number;
    fiber_g?: number;
    sugar_g?: number;
    sodium_mg?: number;
}

export interface FoodLogEntryNew {
    kind: 'new';
    new_food_item: NewFoodItem;
    meal_type: MealType;
    amount: number;
}

export type FoodLogEntry = FoodLogEntryExisting | FoodLogEntryNew;

export class FoodLogDetail extends HTMLElement {
    static get observedAttributes() { return ['mode']; }

    private productValue: OFFProduct | null = null;
    private libraryItemValue: FoodItem | null = null;
    private defaultMealTypeValue: MealType | null = null;
    private modeValue: FoodLogDetailMode = 'log';
    private readonly log = createComponentLogger('food-log-detail');
    private broadcastChannel: BroadcastChannel | null = null;
    /**
     * Set while an image upload is queued and the local row has no
     * `image_path` yet. The pending sentinel lives ONLY in the UI — we never
     * persist it via the API. When the upload completes, the BroadcastChannel
     * handler clears it and adopts the real `image_path`.
     */
    private pendingImageQueueId: string | null = null;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    attributeChangedCallback(name: string, _oldValue: string | null, newValue: string | null): void {
        if (name === 'mode' && newValue) {
            this.modeValue = newValue as FoodLogDetailMode;
            this.applyMode();
        }
    }

    connectedCallback(): void {
        const shadow = this.shadowRoot!;
        shadow.getElementById('back-btn')!.addEventListener('click', () => this.dispatchEvent(createFoodLogBackEvent()));
        shadow.getElementById('log-btn')!.addEventListener('click', () => this.handleLog());
        shadow.getElementById('archive-btn')!.addEventListener('click', () => this.handleArchiveToggle());

        shadow.getElementById('btn-image-add')!.addEventListener('click', () => this.openImagePicker());
        shadow.getElementById('btn-image-replace')!.addEventListener('click', () => this.openImagePicker());
        shadow.getElementById('btn-image-remove')!.addEventListener('click', () => this.handleImageRemove());
        shadow.getElementById('image-input')!.addEventListener('change', (e) => {
            const input = e.target as HTMLInputElement;
            const file = input.files?.[0];
            if (file) this.handleImagePicked(file);
            input.value = '';
        });

        if (typeof BroadcastChannel !== 'undefined') {
            this.broadcastChannel = new BroadcastChannel('motivation-image-uploads');
            this.broadcastChannel.onmessage = (e) => {
                const data = e.data;
                if (!data || data.type !== 'image-upload-success') return;
                const matches = (data.local_ref && data.local_ref === this.libraryItemValue?.id)
                    || (this.pendingImageQueueId && data.queue_id === this.pendingImageQueueId);
                if (matches && this.libraryItemValue) {
                    this.pendingImageQueueId = null;
                    this.libraryItemValue = { ...this.libraryItemValue, image_path: data.image_path };
                    this.renderImage();
                    this.clearImageError();
                }
            };
        }

        this.applyMealTypeSelection();
        this.applyMode();
    }

    disconnectedCallback(): void {
        if (this.broadcastChannel) {
            this.broadcastChannel.close();
            this.broadcastChannel = null;
        }
    }

    set defaultMealType(mealType: string | null) {
        if (!mealType || !MEAL_TYPES.includes(mealType as MealType)) {
            this.defaultMealTypeValue = null;
            this.applyMealTypeSelection();
            return;
        }
        this.defaultMealTypeValue = mealType as MealType;
        this.applyMealTypeSelection();
    }

    set mode(value: FoodLogDetailMode) {
        this.modeValue = value;
        this.applyMode();
    }

    private applyMode(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const mealRow = shadow.getElementById('meal-type-row');
        const logBtn = shadow.getElementById('log-btn');
        if (mealRow) mealRow.hidden = this.modeValue === 'add-ingredient';
        if (logBtn) logBtn.textContent = this.modeValue === 'add-ingredient' ? 'Add to meal' : 'Log Food';
        // Image-action visibility depends on mode (library + log → editable;
        // add-ingredient → read-only thumb only).
        this.renderImage();
        this.renderArchiveState();
    }

    private renderArchiveState(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const archiveBtn = shadow.getElementById('archive-btn') as HTMLButtonElement | null;
        const flag = shadow.getElementById('archived-flag') as HTMLElement | null;
        if (!archiveBtn || !flag) return;

        // Archive lives on the food_items row; only library items in 'log'
        // mode get the action. OFF products and add-ingredient mode skip it.
        const eligible = !!this.libraryItemValue && this.modeValue === 'log';
        archiveBtn.hidden = !eligible;
        if (!eligible) {
            flag.hidden = true;
            return;
        }

        const archived = !!this.libraryItemValue!.archived_at;
        archiveBtn.textContent = archived ? 'Unarchive' : 'Archive';
        flag.hidden = !archived;
    }

    private async handleArchiveToggle(): Promise<void> {
        if (!this.libraryItemValue || this.modeValue !== 'log') return;
        const archived = !!this.libraryItemValue.archived_at;
        try {
            const updated = await HealthService.updateFoodItem(this.libraryItemValue.id, {
                archived_at: archived ? null : Temporal.Now.instant().toString(),
            });
            this.libraryItemValue = updated;
            this.renderArchiveState();
            if (!archived) {
                // The row is now archived and won't appear in the picker;
                // step back so the user lands in the prior screen.
                this.dispatchEvent(createFoodLogBackEvent());
            }
        } catch (err) {
            this.log.error('food archive toggle failed', err);
        }
    }

    showProduct(product: OFFProduct): void {
        this.productValue = product;
        this.libraryItemValue = null;
        const shadow = this.shadowRoot!;
        shadow.getElementById('product-name')!.textContent = product.product_name;
        shadow.getElementById('product-brand')!.textContent = product.brands ?? '';
        this.clearImageError();
        this.renderImage();

        (shadow.getElementById('serving-form') as FoodServingForm).data = offProductToFormData(product);
        this.applyMealTypeSelection();
    }

    showLibraryItem(item: FoodItem, initialAmount?: number): void {
        this.libraryItemValue = item;
        this.productValue = null;
        this.pendingImageQueueId = null;
        const shadow = this.shadowRoot!;
        shadow.getElementById('product-name')!.textContent = item.display_name;
        shadow.getElementById('product-brand')!.textContent = item.brand ?? '';
        this.clearImageError();
        this.renderImage();
        this.renderArchiveState();

        (shadow.getElementById('serving-form') as FoodServingForm).data = foodItemToFormData(item, initialAmount);
        this.applyMealTypeSelection();
    }

    /**
     * Updates the image thumbnail, the image-action button visibility, and
     * the hidden file input wiring based on the current state (library vs
     * OFF) and mode (log vs add-ingredient).
     */
    private renderImage(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const thumb = shadow.getElementById('image-thumb') as HTMLElement;
        const actions = shadow.getElementById('image-actions') as HTMLElement;
        const addBtn = shadow.getElementById('btn-image-add') as HTMLButtonElement;
        const replaceBtn = shadow.getElementById('btn-image-replace') as HTMLButtonElement;
        const removeBtn = shadow.getElementById('btn-image-remove') as HTMLButtonElement;

        thumb.removeAttribute('path');
        thumb.removeAttribute('remote');

        if (this.libraryItemValue) {
            const realPath = this.libraryItemValue.image_path;
            // Show the pending sentinel only when there's no real path yet —
            // food-thumbnail renders the spinner for any value starting
            // with `pending:`. The sentinel never leaves this component.
            const path = realPath ?? (this.pendingImageQueueId ? `pending:${this.pendingImageQueueId}` : null);
            if (path) thumb.setAttribute('path', path);
            thumb.setAttribute('alt', this.libraryItemValue.display_name);

            // Library items in log mode get add/replace/remove. add-ingredient
            // mode is read-only (story 128: thumb visible, no controls).
            const editable = this.modeValue === 'log';
            actions.hidden = !editable;
            if (editable) {
                const hasOrPendingImage = !!path;
                addBtn.hidden = hasOrPendingImage;
                replaceBtn.hidden = !hasOrPendingImage;
                removeBtn.hidden = !hasOrPendingImage;
            }
            return;
        }

        if (this.productValue) {
            if (this.productValue.image_url) thumb.setAttribute('remote', this.productValue.image_url);
            thumb.setAttribute('alt', this.productValue.product_name);
            // OFF products have no row to PATCH yet; controls hidden until
            // adoption creates a food_items row.
            actions.hidden = true;
            return;
        }

        thumb.setAttribute('alt', '');
        actions.hidden = true;
    }

    private openImagePicker(): void {
        const shadow = this.shadowRoot!;
        (shadow.getElementById('image-input') as HTMLInputElement).click();
    }

    private async handleImagePicked(file: File): Promise<void> {
        if (!this.libraryItemValue || this.modeValue !== 'log') return;
        this.clearImageError();
        try {
            const result = await FilesService.uploadImageOrQueue(
                'food',
                file,
                file.name || 'photo.jpg',
                { local_ref: this.libraryItemValue.id },
            );
            if (result.status === 'uploaded') {
                const updated = await HealthService.updateFoodItem(this.libraryItemValue.id, { image_path: result.image_path });
                this.libraryItemValue = updated;
                this.pendingImageQueueId = null;
                this.renderImage();
            } else {
                // Queued — render the spinner locally, but do NOT persist a
                // `pending:` sentinel via the API. The BroadcastChannel
                // handler (and app.ts) will patch the real `image_path` into
                // the local DB and this component's state when the queue
                // ships.
                this.pendingImageQueueId = result.queue_id;
                this.renderImage();
                this.showImageError('Photo will upload when online');
            }
        } catch (err) {
            const message = err instanceof Error ? err.message : String(err);
            this.log.error('food image upload/PATCH failed', err);
            this.showImageError(message);
        }
    }

    private async handleImageRemove(): Promise<void> {
        if (!this.libraryItemValue || this.modeValue !== 'log') return;
        this.clearImageError();
        try {
            const updated = await HealthService.updateFoodItem(this.libraryItemValue.id, { image_path: null });
            this.libraryItemValue = updated;
            this.pendingImageQueueId = null;
            this.renderImage();
        } catch (err) {
            const message = err instanceof Error ? err.message : String(err);
            this.log.error('food image clear failed', err);
            this.showImageError(message);
        }
    }

    private showImageError(message: string): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const error = shadow.getElementById('image-error') as HTMLElement;
        error.textContent = message;
        error.hidden = false;
    }

    private clearImageError(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const error = shadow.getElementById('image-error') as HTMLElement;
        error.textContent = '';
        error.hidden = true;
    }

    private async handleLog(): Promise<void> {
        const form = this.shadowRoot!.getElementById('serving-form') as FoodServingForm;
        const { servingAmount, serving } = form.getCurrentValues();

        if (this.modeValue === 'add-ingredient') {
            // For ingredients, the food item must exist (the meal save flow needs an id).
            const source = this.libraryItemValue ? 'library'
                : this.productValue ? 'off'
                : 'none';
            this.log.debug('handleLog add-ingredient', { source, amount: servingAmount });
            const foodItem = this.libraryItemValue
                ?? (this.productValue
                    ? (this.productValue.barcode ? await HealthService.fetchFoodItemByBarcode(this.productValue.barcode) : null)
                        ?? await HealthService.createFoodItem(offProductToNewFoodItem(this.productValue))
                    : null);
            if (!foodItem) {
                this.log.warn('handleLog add-ingredient: no food item resolved — nothing dispatched');
                return;
            }
            this.dispatchEvent(createAddIngredientEvent({ food_item: foodItem, amount: servingAmount }));
            return;
        }

        if (this.libraryItemValue) {
            this.log.debug('handleLog dispatch', { kind: 'existing', foodItemId: this.libraryItemValue.id, amount: servingAmount });
            this.dispatchEvent(createLogFoodEvent({
                kind: 'existing',
                food_item_id: this.libraryItemValue.id,
                meal_type: this.getSelectedMealType(),
                amount: servingAmount,
                ...serving,
            }));
            return;
        }

        if (this.productValue) {
            // OFF product: send the new-food payload so the parent can call the
            // atomic create+log endpoint. No food row is created if the log fails.
            this.log.debug('handleLog dispatch', { kind: 'new', barcode: this.productValue.barcode, amount: servingAmount });
            this.dispatchEvent(createLogFoodEvent({
                kind: 'new',
                new_food_item: offProductToNewFoodItem(this.productValue),
                meal_type: this.getSelectedMealType(),
                amount: servingAmount,
            }));
            return;
        }

        this.log.warn('handleLog: no library item or OFF product set — nothing dispatched');
    }

    private applyMealTypeSelection(): void {
        const mealSelect = this.shadowRoot?.getElementById('meal-type') as HTMLSelectElement | null;
        if (mealSelect) {
            mealSelect.value = this.defaultMealTypeValue ?? getDefaultMealType();
        }
    }

    private getSelectedMealType(): MealType {
        return ((this.shadowRoot?.getElementById('meal-type') as HTMLSelectElement | null)?.value as MealType) ?? getDefaultMealType();
    }
}

customElements.define('food-log-detail', FoodLogDetail);
