import stylesText from './food-log.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { formatMacro } from '../../../utils/format-macro.js';

const styles = cssStyleSheet(stylesText);
import type { FoodItem, Meal } from '@motivation/shared';
import type { OFFProduct } from '../../../services/openfoodfacts.service.js';
import {
    HEALTH_EVENTS,
    createSelectLibraryItemEvent,
    createSelectMealEvent,
    createSelectOffItemEvent,
    createLoadMoreOffEvent,
} from '../health-events.js';
import '../food-thumbnail/food-thumbnail.component.js';

const template = document.createElement('template');
template.innerHTML = `
    <div class="search-results" id="search-results"></div>
`;

export class FoodSearchResults extends HTMLElement {
    private libraryItemsValue: FoodItem[] = [];
    private offItemsValue: OFFProduct[] = [];
    private mealsValue: Meal[] = [];
    private showLoadMoreValue = false;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    set libraryItems(value: FoodItem[]) {
        this.libraryItemsValue = value;
        this.render();
    }

    set offItems(value: OFFProduct[]) {
        this.offItemsValue = value;
        this.render();
    }

    set meals(value: Meal[]) {
        this.mealsValue = value;
        this.render();
    }

    set showLoadMore(value: boolean) {
        this.showLoadMoreValue = value;
        this.render();
    }

    appendOffItems(items: OFFProduct[]): void {
        this.offItemsValue = [...this.offItemsValue, ...items];
        this.render();
    }

    clear(): void {
        this.libraryItemsValue = [];
        this.offItemsValue = [];
        this.mealsValue = [];
        this.showLoadMoreValue = false;
        this.render();
    }

    showEmpty(message: string): void {
        const container = this.shadowRoot!.getElementById('search-results')!;
        container.replaceChildren();
        const empty = document.createElement('p');
        empty.className = 'empty-state';
        empty.textContent = message;
        container.appendChild(empty);
    }

    private render(): void {
        const container = this.shadowRoot!.getElementById('search-results')!;
        container.replaceChildren();

        if (this.mealsValue.length > 0) {
            container.appendChild(this.createSectionLabel('Meals'));
            for (const meal of this.mealsValue) {
                container.appendChild(this.createMealRow(meal));
            }
        }

        if (this.libraryItemsValue.length > 0) {
            container.appendChild(this.createSectionLabel('Your Library'));
            for (const item of this.libraryItemsValue) {
                container.appendChild(this.createLibraryRow(item));
            }
        }

        if (this.offItemsValue.length > 0) {
            container.appendChild(this.createSectionLabel('Open Food Facts'));
            for (const item of this.offItemsValue) {
                container.appendChild(this.createOffRow(item));
            }

            if (this.showLoadMoreValue) {
                const btn = document.createElement('button');
                btn.className = 'load-more-btn';
                btn.textContent = 'Load More Results';
                btn.addEventListener('click', () => {
                    btn.disabled = true;
                    btn.textContent = 'Loading…';
                    this.dispatchEvent(createLoadMoreOffEvent());
                });
                container.appendChild(btn);
            }
        }
    }

    private createSectionLabel(text: string): HTMLElement {
        const label = document.createElement('p');
        label.className = 'result-section-label';
        label.textContent = text;
        return label;
    }

    private createThumb(opts: { path?: string | null; remote?: string | null; alt: string }): HTMLElement {
        const thumb = document.createElement('food-thumb');
        if (opts.path) thumb.setAttribute('path', opts.path);
        else if (opts.remote) thumb.setAttribute('remote', opts.remote);
        thumb.setAttribute('alt', opts.alt);
        return thumb;
    }

    private createMealRow(meal: Meal): HTMLElement {
        const row = document.createElement('div');
        row.className = 'search-result-item meal-result';

        row.appendChild(this.createThumb({ path: meal.image_path, alt: meal.name }));

        const info = document.createElement('div');
        info.className = 'result-info';

        const nameRow = document.createElement('div');
        nameRow.className = 'result-name';
        const badge = document.createElement('span');
        badge.className = 'meal-badge';
        badge.textContent = 'Meal';
        nameRow.appendChild(badge);
        nameRow.appendChild(document.createTextNode(' ' + meal.name));

        const subtitle = document.createElement('div');
        subtitle.className = 'result-brand';
        subtitle.textContent = meal.notes ?? '';

        info.appendChild(nameRow);
        info.appendChild(subtitle);
        row.appendChild(info);
        row.addEventListener('click', () => this.dispatchEvent(createSelectMealEvent(meal)));
        return row;
    }

    private createLibraryRow(item: FoodItem): HTMLElement {
        const row = document.createElement('div');
        row.className = 'search-result-item';

        row.appendChild(this.createThumb({ path: item.image_path, alt: item.display_name }));

        const info = document.createElement('div');
        info.className = 'result-info';

        const name = document.createElement('div');
        name.className = 'result-name';
        name.textContent = item.display_name;

        const brand = document.createElement('div');
        brand.className = 'result-brand';
        brand.textContent = item.brand ?? item.serving_label ?? '';

        const cal = document.createElement('div');
        cal.className = 'result-cal';
        cal.textContent = `${formatMacro(foodItemCaloriesForDisplay(item))} kcal`;

        info.appendChild(name);
        info.appendChild(brand);
        row.appendChild(info);
        row.appendChild(cal);
        row.addEventListener('click', () => this.dispatchEvent(createSelectLibraryItemEvent(item)));
        return row;
    }

    private createOffRow(item: OFFProduct): HTMLElement {
        const row = document.createElement('div');
        row.className = 'search-result-item';

        row.appendChild(this.createThumb({ remote: item.image_url, alt: item.product_name }));

        const info = document.createElement('div');
        info.className = 'result-info';

        const name = document.createElement('div');
        name.className = 'result-name';
        name.textContent = item.product_name;

        const brand = document.createElement('div');
        brand.className = 'result-brand';
        brand.textContent = item.brands ?? '';

        const cal = document.createElement('div');
        cal.className = 'result-cal';
        cal.textContent = `${formatMacro(item.calories_per_100g ?? 0)} kcal`;

        info.appendChild(name);
        info.appendChild(brand);
        row.appendChild(info);
        row.appendChild(cal);
        row.addEventListener('click', () => this.dispatchEvent(createSelectOffItemEvent(item)));
        return row;
    }
}

/**
 * Display-only "calories at a glance" for a search row. For weight-based
 * (g) items we show kcal/100g; for everything else we show kcal at the food
 * item's `default_serving_amount` (or one base unit). The value is illustrative
 * — actual logging asks for an explicit amount.
 */
function foodItemCaloriesForDisplay(item: FoodItem): number {
    const perBase = item.calories_per_base ?? 0;
    if (item.base_unit === 'g' && item.base_amount > 0) {
        return (perBase * 100) / item.base_amount;
    }
    return perBase * ((item.default_serving_amount ?? item.base_amount) / item.base_amount);
}

customElements.define('food-search-results', FoodSearchResults);
